dataKeys.funcBody:
// Monthly P90 baseline (emits value PER MONTH)
var p90_annual = 1350000; // kWh
var tariff = 22;          // LKR

var annual_revenue_M = (p90_annual * tariff) / 1000000;
var monthly_baseline = annual_revenue_M / 12;

// IMPORTANT:
// Use `time` so ThingsBoard creates a time series point
return monthly_baseline;

var p90_annual = 1350000;
var tariff = 22;

var baseline = (p90_annual * tariff) / 1000000 / 12;

// Month-based deterministic seasonality (IMPORTANT)
var date = new Date(time);
var month = date.getMonth(); // 0–11

// Stable sinusoidal curve (no randomness = repeatable)
var seasonality = Math.sin((month / 11) * Math.PI); // 0 → 1 → 0

var variance = (seasonality * 0.35) - 0.1; // -10% to +25%

return baseline * (1 + variance);

