settings.nodeOpenedFunction:
var entity = nodeCtx.entity;

// Use the ID of your default device (find this from the ThingsBoard entity list)
var defaultDeviceId = '783e5900-45af-11ef-b4ce-d5aee9e495ad';

// Check if the current entity matches the default device and open it
if (entity.id.id === defaultDeviceId) {
    return true; // Open this device by default
} else {
    return nodeCtx.level <= 2; // Default behavior for other nodes (first level nodes open)
}

